+fn cast_numpy_array_dtype(
+    py: Python<'_>,
+    array: Py<PyAny>,
+    dtype: &Bound<'_, PyAny>,
+) -> PyResult<Py<PyAny>> {
+    Ok(array
+        .bind(py)
+        .call_method(
+            "astype",
+            (dtype,),
+            Some(&{
+                let kwargs = PyDict::new(py);
+                kwargs.set_item("copy", false)?;
+                kwargs
+            }),
+        )?
+        .unbind())
+}
